var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 15일 런던, <color=#ffd34c>베이커 가 211번지</color>","JPN":"1888年10月15日　ロンドン、<color=#ffd34c>ベーカー街211番地</color>","ENG":"October 15, 1888, London, <color=#ffd34c>211 Baker St.</color>","TWN":"1888年10月15日 倫敦，<color=#ffd34c>貝克街211號</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"도착했네.","JPN":"着いた。","ENG":"We've arrived.","TWN":"到了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"오랜만에 손님이로군. 누추하지만 안으로 들게.","JPN":"久々の客人だな。汚いが、どうぞ入ってくれ。","ENG":"It's been a long time since I had a guest. Please, make yourself at home.","TWN":"好久沒有客人了。雖然簡陋，但請進吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"여긴 어디죠?","JPN":"ここはどこですか？","ENG":"Where are we?","TWN":"這是……哪裡？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 오랜 아지트 같은 곳이지. 여기라면 일단 쫓길 일은 없을 거야.","JPN":"私の古いアジトのようなところだ。ここならまず追われることはないだろう。","ENG":"It's my old hideout. No one will be on our tail while we're here.","TWN":"這裡是我以前的藏身之處。在這裡暫時不會被追上。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마도구를 써서 인식을 저해해 두었어. 보통 사람들에게는 평범한 하숙집으로 보이겠지.","JPN":"魔道具を使って認識を阻害しておいた。普通の人間にはそこらの下宿屋に見えるはずだ。","ENG":"I used a Curio to hinder people's perception. To ordinary people, this place will look like a normal boarding home.","TWN":"因為用特殊工具干擾了感知。在普通人看來，這裡只是個普通的寄宿房而已。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"인식을 저해한다고요? 그만한 마도구를 어디서……?","JPN":"認識を阻害する？　そんな魔道具をどこで……？","ENG":"Hinder people's perception? Where did you find a Curio that potent...?","TWN":"干擾感知？那樣的特殊工具是從哪裡……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 자네보다야 덜 하겠지만 나도 제법 인기가 있는 편이거든.","JPN":"ハハ、君ほどではないが私は結構モテるものでね。","ENG":"Haha, it might not be up to your level, but I'm also rather popular.","TWN":"呵呵，雖然比不上你，但我也算是相當受歡迎的喔。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 내 목숨을 노리는 범죄자들 한정이지만.","JPN":"もちろん、私の命を狙っている犯罪者限定だが。","ENG":"But only to criminals who want me dead, of course.","TWN":"當然，僅限那些想要我命的罪犯。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 자랑할 일이에요?","JPN":"それって、自慢にならないでしょう？","ENG":"I don't think that's something to be proud of.","TWN":"那是值得炫耀的事嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그보다 스완…….","JPN":"それより、スワン……","ENG":"Anyway, Swan...","TWN":"比起這個，史旺……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"벽장 두번째 서랍에 있는 약물과 주사기를 부탁할 수 있을까?","JPN":"クローゼットの二番目の引き出しにある薬物と注射器をお願いできるかね？","ENG":"Could you bring me my medicine and syringe in the second drawer of the closet?","TWN":"能幫我拿一下壁櫥第二層裡的藥物和注射器嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제 슬슬 한계라서 말이지.","JPN":"もうそろそろ限界だ。","ENG":"I'm at my limit right now.","TWN":"現在差不多到極限了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이거 맞죠?","JPN":"これですよね？","ENG":"Is this it?","TWN":"你確定是這個嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 고맙네. 다행히 아직 잔량이 남아있군.","JPN":"そうだ、ありがとう。幸い、まだ残ってるな。","ENG":"Yes. Thank you. Thankfully, there is still some left.","TWN":"是的，謝謝。幸好還有剩餘。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후우우우우…….","JPN":"ふうううう……","ENG":"Phew...","TWN":"呼——"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 그게 뭐죠? 평범한 약물처럼 보이지는 않는데?","JPN":"それ、いったいなんですか？　普通の薬には見えませんけど。","ENG":"What is that? It doesn't look like any ordinary medicine.","TWN":"那到底是什麼？看起來不像是普通的藥物啊？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마석을 정제하여 순도 높은 각성제와 배합한 <color=#ffd34c>주사액</color>이라네.","JPN":"魔石を精製して高純度の覚醒剤と調合した<color=#ffd34c>注射液</color>だ。","ENG":"It's a <color=#ffd34c>concoction</color> made of refined Mana Stones and high-purity stimulants.","TWN":"那是將魔石精煉後與高純度興奮劑混合製成的<color=#ffd34c>注射液</color>。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수년 전, 내 오랜 벗이 이곳을 떠나기 전에 만들어 둔 거지.","JPN":"数年前、私の旧友がここを出る前に作っておいたものさ。","ENG":"Years ago, an old friend of mine made it before leaving this place.","TWN":"幾年前，我的一個老友在離開這裡之前製作的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이게 없으면, 이제 정상적인 생활이 불가능하거든.","JPN":"もうこれがないと、正常な暮らしができなくてね。","ENG":"Without it, I'm unable to function normally now.","TWN":"沒有這個，現在就無法正常生活了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고요……?","JPN":"なんですって……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 그럴지도 모르겠군.","JPN":"はは、そうかもしれないな。","ENG":"Haha, perhaps it is.","TWN":"哈哈，也許吧。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"부디, 무례를 용서해주게. 내게 허락된 시간이 이제 얼마 남지 않았거든.","JPN":"どうか無礼を許してくれたまえ。もう私に残された時間があまりないのだ。","ENG":"But please forgive my rudeness. My time is running out.","TWN":"請原諒我的無禮。但留給我的時間已經不多了。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 설마 시간이 없다는 말이……?","JPN":"じゃあ、まさか時間がないというのは……？","ENG":"Then, what you meant by your time running out is...","TWN":"難道說時間不夠了，是這個意思……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐, 이런저런 사건들을 해결하면서 얻은 <color=#ffd34c>직업병</color> 같은 거라네.","JPN":"まあ、あらゆる事件を解決しながら身についた<color=#ffd34c>職業病</color>のようなものだ。","ENG":"Well, it's like an <color=#ffd34c>occupational hazard</color> that I got from solving various cases.","TWN":"嘛，這是解決各種案件時得來的，我猜也算是<color=#ffd34c>職業病</color>一樣的東西吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왕실에서 정보를 통제하고 있어, 대중들에게는 공개되지 않았지만.","JPN":"王室で情報を統制していて、大衆には公開されてはいないのだが。","ENG":"The royal family is controlling the information, so the public doesn't know about it yet.","TWN":"王室在控制資訊，雖然沒有向大眾公開。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왕실 의사들은 이걸 <color=#ffd34c>침식병</color>이라고 한다지.","JPN":"王室の医者たちはこれを<color=#ffd34c>侵食病</color>と呼ぶらしい。","ENG":"The royal doctors seem to call this the <color=#ffd34c>Corruption Syndrome</color>.","TWN":"皇家醫生把這個稱為<color=#ffd34c>侵蝕病</color>。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"침식병이라고요!?","JPN":"侵食病！？","ENG":"Corruption Syndrome?!","TWN":"侵蝕病！？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"들어 본 적 있어요. 침식병은 불치병이잖아요! 뭘 대수롭지 않은 척하는 건데요!","JPN":"聞いたことあります。侵食病って不治の病じゃないですか！　何を平然と話してるんですか！？","ENG":"I've heard of that before. The Corruption Syndrome is incurable! Why are you acting like it's nothing?!","TWN":"我聽說過這個，侵蝕病可是絕症啊！你怎麼能裝作一副無所謂的樣子！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼 지금까지 그런 몸으로, 사건인지 뭔지를 해결하고 다녔다는 거예요?","JPN":"じゃあ今までその体で、事件とかを解決してたんですか？","ENG":"Then, you were going around solving these cases in that state?","TWN":"那就是說，你一直拖著這樣的身體，偵破了那些案件嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당장 죽어도 이상하지 않을 몸으로? 수상한 약까지 맞아가면서?","JPN":"すぐ倒れてもおかしくない体で？　怪しい薬まで打ってまで？","ENG":"When it wouldn't be strange if you died right now? And even taking that suspicious medicine?","TWN":"用一副隨時可能死去的身體？還注射了可疑的藥物？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제정신이에요? 그러다가 죽는다고요!","JPN":"正気ですか？　死んじゃいますよ！","ENG":"Are you mad? You're going to die if you keep this up!","TWN":"你瘋了嗎？這樣真的會死的好吧！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 이거 의외로군. 내 걱정을 해주는 건가?","JPN":"ハハ、これまた意外だな。私を心配してくれるのか？","ENG":"Haha, this is unexpected. Are you worried about me right now?","TWN":"哈哈，這真是意外啊。你是在關心我嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 날 싫어하는 줄 알았는데?","JPN":"君は私を嫌っていると思ってたのだが。","ENG":"And here I thought that you hated me.","TWN":"我還以為你討厭我呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"싫어해요! 당신의 그런 태도가 싫다고요!","JPN":"嫌いです！　あなたのそういう態度が嫌いなんです！","ENG":"I do hate you! I hate that attitude of yours!","TWN":"我討厭你那樣的態度！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜 자꾸 상관도 없는 타인의 인생에 간섭하려고 하는 거죠?","JPN":"なんで何の関係もない他人の人生に首を突っ込むんですか？","ENG":"Why are you trying to interfere with people's lives that have nothing to do with you?","TWN":"為什麼總是要干涉不相干的人的人生呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 오지랖 부려서 당신에게 남는 게 뭔가요? 부? 명예? 그것도 아니라면…….","JPN":"そんなにお節介を焼いて、あなたが得るものって一体何？　富？　名誉？　それとも……","ENG":"What do you get out of being nosy? Wealth? Fame? If it's not those two–","TWN":"你這麼多管閒事，到底能得到什麼？財富？名譽？如果都不是的話……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"인연이라네.","JPN":"絆だ。","ENG":"Relationships.","TWN":"是緣分。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"인연……?","JPN":"絆……？","ENG":"Relationships...?","TWN":"緣分……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"말하지 않았나, 스완.","JPN":"言ったではないか、スワン。","ENG":"Didn't I say, Swan?","TWN":"我不是說過了嗎，史旺。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리의 운명이라는 보이지 않는 실타래 속에는 사실, 선홍색의 실이 얽혀 있다는 걸.","JPN":"私たちの運命という目に見えない糸には、深紅に染まった糸が絡まっている。","ENG":"It's that within the invisible threads of destiny, our fates are actually intertwined by a bright red thread.","TWN":"在我們那個名為命運的無形線團裡，其實還纏繞著一根鮮紅色的細線。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언뜻 보면, 전혀 상관없는 것들이……. 복잡하게 얽히고 얽혀 어떤 사건을 만들어 내지.","JPN":"最初は何の関係もなく思えても……いつしか複雑に絡み合い、ある出来事を作り出す。","ENG":"The things that seem unrelated at first glance... get tangled together to create an event.","TWN":"乍一看，是完全無關的事物……複雜地交織在一起，才製造出了某種事件。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"인연도 마찬가지야.","JPN":"絆も同じさ。","ENG":"Relationships are the same.","TWN":"緣分也是如此。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아무런 의미 없이 베푼 선행이라 해도, 먼 훗날 그게 어떻게 돌아올지는 아무도 모르지.","JPN":"なんの意味もなく施した善行であっても、遠い未来にそれがどのような形で帰ってくるかは誰にもわからない。","ENG":"Even if my good deeds seem meaningless now, no one knows how it will change the future.","TWN":"即使是無意間的善行，誰也不知道它將來會以什麼方式回報。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네도 그런 경험이 한 번쯤은 있지 않나?","JPN":"君も一度くらいはそのような経験があるのではないか？","ENG":"Haven't you ever had an experience like that before?","TWN":"你不也有過這樣的經歷嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"이건, 티켓이잖아? 스완이 나오는 공연 암표는 부르는 게 값이라고 들었는데……?","JPN":"これはチケット？　スワンが出演する公演のチケットはものすごく高く売れるって聞いたけど……","ENG":"It's a ticket. I heard that tickets to Swan's performances can be sold at absurd prices...!","TWN":"這……這是門票？聽說有天鵝演出的票可是有價無市的……？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PAPERBOY_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그런데 괜찮아? 나 오페라 같은 건 하나도 몰라.","JPN":"で、でもいいの？　僕、オペラなんて全然わからないよ。","ENG":"A-are you sure? I don't know a thing about opera.","TWN":"那、那個沒關係嗎？我對歌劇一竅不通。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 잘 몰라도 상관없어.","JPN":"ふふ、わからなくても大丈夫。","ENG":"HaHa. It doesn’t matter.","TWN":"呵呵，不懂也沒關係。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"공연이라는 건 눈으로 보고, 귀로 듣지만, 결국에는 마음으로 느끼는 거니까.","JPN":"オペラは目で見て、耳で聞くけど、結局は心で感じるものだから。","ENG":"Performances might all be about what you see and hear, but ultimately, it's about what you feel in your heart.","TWN":"演出是用眼睛看，用耳朵聽，但最終是用心去感受的。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CARNELIAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말 이렇게 비싼 표를 그냥 받아도 될까?","JPN":"こんなに高いチケット、本当にタダでもらってもいいのかしら？","ENG":"Are you sure I can have this ticket? It's so expensive one.","TWN":"真的可以接受這麼貴的票嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARNELIAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CARNELIAN_SWANSONG_NPC_NULL","text":{"KOREA":"난 해줄 수 있는 게 아무것도 없는데…….","JPN":"私はなにもしてあげられないのに……","ENG":"And there's nothing I can do for you...","TWN":"我什麼都報答不了……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARNELIAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 말씀이세요. 이렇게 아름다운 초상화를 그려주셨는데.","JPN":"そんなこと言わないでください。こんなに美しい肖像画を描いてくれたじゃないですか。","ENG":"What are you talking about? You painted this lovely portrait of me.","TWN":"你在說什麼呢？你為我畫了這麼美麗的肖像畫。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"동생분께서 저희 공연을 보고 싶다고 하셨다면서요. 그렇다면 오히려 영광이랍니다.","JPN":"妹さんが私たちの公演を見たいって言ったでしょう？　なら、むしろ光栄です。","ENG":"You said that your sister wanted to see my show. It would be an honor if you both came to see it.","TWN":"聽說你妹妹也想看我的演出。那真是我的榮幸。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"관객이 있어야, 비로소 배우가 있는 법이니까요.","JPN":"観客がいてこその俳優ですから。","ENG":"For only when there is an audience, can there be an actress.","TWN":"有觀眾，才有演員。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 뛰어난 해결사라고 해도, 혼자서 모든 것을 해결할 수는 없어.","JPN":"いくら立派な解決屋であっても、一人ですべてを解決することはできない。","ENG":"No matter how skilled one is as a problem solver, one can't solve everything on one's own.","TWN":"再優秀的問題解決者，也無法獨自解決所有的難題。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"경찰 같은 조직력이 없는, 나 같은 자문 탐정이라면 더욱 그렇지.","JPN":"警察のような組織のない、私のような諮問探偵ならなおさらだ。","ENG":"That's especially true for a consulting detective like me who has no organizational support, such as the police.","TWN":"像我這樣的顧問偵探，沒有員警那樣的組織能力，更是如此。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇기에 타인을 도와서, 인연을 만들어 두는 거라네.","JPN":"だからこそ他人を助け、絆を築いておくのだ。","ENG":"That is why I help people and build relationships.","TWN":"正因為這樣，我才會幫助他人，結下緣分。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"과거에 맺었던 인연들은, 틀림없이 미래의 다른 사건을 해결하는데 도움이 될 테니까.","JPN":"過去の絆は、きっと未来の他の事件を解決するのに役立つはずだから。","ENG":"The relationships we made in the past will undoubtedly become helpful in solving other cases in the future.","TWN":"過去結下的緣分，必定會對未來解決其他事件有所幫助。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"종종 그런 생각하곤 해.","JPN":"私はたまに思う。","ENG":"I often think about this.","TWN":"我時常會有那樣的想法。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 이 세상의 모든 것은 보이지 않는 실로 연결되어 있는 게 아닐까 하고 말이야.","JPN":"結局、この世のすべては見えない糸で繋がっているのではないかと。","ENG":"In the end, this world is connected by invisible threads, I think.","TWN":"最終，這個世界上的一切，是不是都被一根看不見的線連接在一起了？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 역으로 세상을 바꾸기 위해서, 개인이 할 수 있는 건 하나뿐이겠지.","JPN":"なら、逆に世界を変えるために、個人ができるのはただ一つしかない。","ENG":"So, thinking about it backwards and how to change the world, there's only one thing an individual can do.","TWN":"那麼，為了改變世界，我個人能做的只有一件事。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"바로 자신과 연결된 다른 인연을 외면하지 않는 것.","JPN":"自分と繋がった絆から目を背けないこと。","ENG":"That is to not neglect the relationship one creates with others.","TWN":"那就是不要回避與自己相連的其他緣分。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 인연들이 조금씩 쌓이고, 또 쌓인다면…….","JPN":"そうやって絆を少しずつ積み重ねていけば……","ENG":"And as one builds relationships one after another...","TWN":"這樣一來，緣分會一點點積累，再積累……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그들이 베푼 선의가 쌓이고, 쌓인다면 정말로 세상을 바꿀 수 있을지도 모르니까.","JPN":"そして彼らの善意が積み重なっていけば、本当に世界を変えることができるかもしれないから。","ENG":"The good deeds that one gave will accumulate, and perhaps really change the world.","TWN":"如果每個人的善意能不斷疊加起來的話，真的有可能改變這個世界吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"후후, 상관없다니 그거 섭섭한 소리네.","JPN":"ふふ、関係ないだなんて悲しいこと言うね。","ENG":"Haha, you're upsetting me by saying that this has nothing to do with me.","TWN":"呵呵，你說無所謂，那可真讓人傷心啊。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"나는 네 전속 스태프이고, 너는 우리 극단을 대표하는 프리마돈나인걸?","JPN":"私はあなたの専属スタッフで、あなたは我が劇団を代表するプリマドンナなのよ？","ENG":"I'm your personal staff, and you're the prima donna that represents our theater.","TWN":"我是你的專屬助理，而你是我們劇團的首席女主角喔？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐……?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"속였다고 해도 상관없어. 기만이라고 해도 괜찮아.","JPN":"騙されたとしても構わない。欺かれたとしても大丈夫。","ENG":"Call it deceiving or fraud, I don't really care.","TWN":"就算被騙了也沒關係，就算是利用也沒關係……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"왜냐하면 무대 위에서 너는 정말로 아름답게 빛났으니까.","JPN":"だって、舞台の上のあなたは本当に美しく輝いていたから。","ENG":"Because you were always shining so brilliantly up on stage.","TWN":"因為在舞台上的你，真的非常閃耀、非常美麗。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"그래, 마치 백조처럼.","JPN":"そう、まるで白鳥みたいに。","ENG":"Yes, you were literally a swan.","TWN":"是的，就像天鵝一樣。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 당신은요?","JPN":"じゃあ、あなたは？","ENG":"Then, what about you?","TWN":"那你呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"오지랖이란 오지랖은 다 부려서, 이미 만신창이가 되어버린 당신은 누가 도와주죠?","JPN":"お節介を焼きすぎちゃって、満身創痍になってしまったあなたを誰が助けるんですか？","ENG":"You put your nose in everyone's business, and your body is completely tattered. But who will help you?","TWN":"真是多管閒事啊，已經弄得遍體鱗傷的你，又有誰來幫你呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 글쎄……?","JPN":"はは、それはどうかな……？","ENG":"Haha, I don’t know.","TWN":"哈哈，這個還真的不知道……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 말하지 않았나. 수수께끼 풀이가 내 업이라고.","JPN":"だが、言ったではないか。謎解きが私の仕事だと。","ENG":"But didn't I say? It's my job to solve mysteries.","TWN":"但是我不是說過了嗎？解謎是我的工作。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나 자신이 원해서 선택한 일이야.","JPN":"私自身が望んで選択したことだ。","ENG":"I chose this because it is something I want to do.","TWN":"這是我自己的選擇。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"공공의 이익을 위해서라면 나는 어떤 결말을 맞이하더라도 받아들일 준비가 되어있네.","JPN":"公共の利益のためなら、私はどんな結末を迎えようとも受け入れる準備ができている。","ENG":"I'm prepared to accept any outcome if it is for the public good.","TWN":"為了更大的利益，我已經準備好了接受任何結局。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후우우.","JPN":"ふう。","ENG":"Whew.","TWN":"呼——"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"좋아. 자네와 이야기 나누니, 이제야 머리가 개운해졌군.","JPN":"よし。君と話したら、やっと頭がすっきりした。","ENG":"All right. Chatting with you seems to have cleared my head a little.","TWN":"好，和你聊完天，現在感覺頭腦清醒多了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 상태가 나쁘지 않을 때 이야기를 들어두도록 할까?","JPN":"では、コンディションが悪くないうちに話を聞いておこうではないか。","ENG":"Then, shall I listen to yours before my condition worsens again?","TWN":"那麼，在狀態還沒惡化的時候先聽聽情況吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 정보에 따르면, 심야의 살인마의 네번째 현장을 목격한 게 자네라고 하던데.","JPN":"私の情報によれば、深夜の殺人鬼の四番目の現場を目撃したのは君らしいじゃないか。","ENG":"According to my information, you are the one who saw the Midnight Killers' fourth murder scene.","TWN":"根據我的情報，你目擊了午夜殺人魔作案的第四現場。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그날의 이야기를 들려주겠나?","JPN":"その日の話を聞かせてくれるか？","ENG":"Can you elaborate about that day?","TWN":"能講講那天的事嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……알겠어요.","JPN":"……わかりました。","ENG":"...Okay.","TWN":"……知道了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……그렇군.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"사건 현장에 검은 갑옷을 입은 기사가 나타났다는 말이지.","JPN":"事件の現場に黒い鎧をまとった騎士が現われたと。","ENG":"A knight in black armor appeared on the scene, you say.","TWN":"聽說案發現場出現了一個黑色盔甲的騎士。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지난 증언과 일치하군. 하지만 그 검은 갑옷은 심야의 살인마가 아닐 걸세.","JPN":"今までの証言と一致している。だが、その黒い鎧は深夜の殺人鬼ではないだろう。","ENG":"It matches with the previous testimony. But that black armor is not the Midnight Killer.","TWN":"和之前的證詞一致。不過，那黑色盔甲應該不是午夜殺人魔的吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 소리죠? 제가 똑똑히 봤다고요.","JPN":"何を言ってるんですか。はっきり見たんですよ、私。","ENG":"What do you mean? I saw it with my own eyes.","TWN":"啊？為什麼？我明明看得很清楚。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건 틀림없은 마물이었어요. 심야의 살인마의 정체는 인간이 아니었다고요.","JPN":"あれは間違いなく魔物でした。深夜の殺人鬼の正体は、人間じゃなかったんです。","ENG":"It was definitely a monster. The Midnight Killer wasn't human.","TWN":"那個人絕對是怪物吧？午夜殺人魔的真面目不是人類。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언제나 냉정하게 생각하게, 스완. 그 정체가 인간인지, 마물인지 그런 건 중요하지 않아.","JPN":"常に冷静に考えたまえ、スワン。その正体が人間か魔物か、そんなことが重要なのではない。","ENG":"Always think rationally, Swan. It doesn't matter if it is a human or a monster.","TWN":"保持冷靜思考，史旺。殺人魔的真面目是人類還是怪物並不重要。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"중요한 건 흉기지.","JPN":"凶器が重要なのだ。","ENG":"What's important is the murder weapon.","TWN":"重要的是兇器。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흉기?","JPN":"凶器？","ENG":"Murder weapon?","TWN":"兇器？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"목 위가 통째로 사라진 네 번째 피해자를 제외하면, 지금까지는 날카로운 날붙이에 의해 시체가 훼손되었어.","JPN":"首から上が丸ごとなくなった四番目の被害者を除けば、今までは鋭い刃物によって死体の一部が損傷された。","ENG":"Excluding the fourth victim who was beheaded, all the other corpses were mutilated with a sharp blade.","TWN":"除了第四個脖子被切斷的受害者外，到目前為止，屍體都是被鋒利的刀具肢解的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 검은 갑옷이 큰 칼을 들고 있었다고 했지?","JPN":"君は黒い鎧が大きな刃物を持っていたと言ってたな？","ENG":"You said that the black armor was carrying a large sword, right?","TWN":"你說你看到的那個人拿著一把大劍，對嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 정도로 큰 칼에 맞으면, 결코 시체가 훼손되는 정도로는 끝나지 않을 거야.","JPN":"だが、それほど大きな刃物で斬られたら、死体に傷がつくほどでは済まないだろう。","ENG":"But being slashed by a sword of that size will not just mutilate a part of a corpse.","TWN":"但是，如果被那麼大的刀砍中，屍體絕對不會保留得那麼完整。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"확실히…….","JPN":"確かに……","ENG":"You're right...","TWN":"確實……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"또한 전신 갑옷을 입고 있었다면, 증표를 절단해야 하는 세심한 작업은 힘들겠지.","JPN":"また全身鎧をまとっていたなら、印を切断するなどの繊細な作業は困難なはず。","ENG":"Also, wearing full body armor will make it difficult to precisely cut out the marks.","TWN":"而且，如果穿著全身盔甲的話，要進行切除標記的細緻工作就會很困難。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 검은 갑옷이 심야의 살인마라는 가정은 무리가 있어.","JPN":"結局、黒い鎧が深夜の殺人鬼であるという仮定では無理がある。","ENG":"In conclusion, it's unreasonable to assume that the black armor is the Midnight Killer.","TWN":"總之，假設黑色盔甲是午夜殺人魔，這個推測有些牽強。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 현장에 남아있던 메시지들은요? 그건 어떻게 된 건가요?","JPN":"じゃあ、現場に残っていたメッセージは？　あれはどういうことですか？","ENG":"Then, what about the messages left behind at the scenes? What about them?","TWN":"那麼，現場留下的那些塗鴉呢？那些是怎麼回事？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"메시지라…….","JPN":"メッセージか……","ENG":"Messages, you say...","TWN":"塗鴉嗎……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세 번째 피해자, 리사 스트라우드 29세, 12월 3일생. 대퇴부가 훼손.","JPN":"三番目の被害者リサ・ストラウド、29歳、12月3日生まれ。大腿部が損傷。","ENG":"The third victim, Lisa Stroud. Twenty-nine years old, born on December 3rd. Her thigh was mutilated.","TWN":"第三名受害者，麗莎·斯特勞德，29歲，12月3日出生。大腿部受損。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"현장의 메시지는 <color=#ffd34c>세 번째 시련을 지나라, 그녀는 녹슬지 않은 주석과 같이 될지니.</color>","JPN":"現場のメッセージは<color=#ffd34c>三つ目の試練を越えろ。彼女は錆びない錫のようになるだろう。</color>","ENG":"The message at the scene said, \\"<color=#ffd34c>Pass the third ordeal, for she will become like tin that does not rust.\\"</color>","TWN":"現場留下的塗鴉是，<color=#ffd34c>經歷第三之裁判，她將如不鏽的錫。</color>"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"네 번째 피해자, 케이트 우드 15세, 4월 25일생. 머리 및 후두가 훼손.","JPN":"四番目の被害者ケイト・ウッド、15歳、4月25日生まれ。頭および後頭部が損傷。","ENG":"The fourth victim, Kate Wood. Fifteen years old, born on April 25th. Her head and voice box were mutilated.","TWN":"第四位受害者，凱特·伍德，15歲，4月25日出生。頭部及喉部受損。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"메시지는 <color=#ffd34c>네 번째 시련을 지나라, 그녀는 불꽃에 달궈진 철이 될지니.</color>","JPN":"メッセージは<color=#ffd34c>四つ目の試練を越えろ、彼女は炎で煉られた鉄になるだろう。</color>","ENG":"The message said, <color=#ffd34c>\\"Pass the fourth ordeal, and she will become iron heated in flame.\\"</color>","TWN":"塗鴉是<color=#ffd34c>經歷第四之裁判，她將會是淬火的鐵。</color>"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 이 메시지의 메타포와 피해자의 관계는 전부 알아냈다네.","JPN":"もちろん、このメッセージのメタファーと被害者の関係は全部突き止めた。","ENG":"Of course, I have figured out the metaphors of the messages and their relation to the victims.","TWN":"當然，這幾條資訊包含的隱喻以及受害者的關係我都弄清楚了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 다음 범행이 심야의 살인마 최후의 살인이 되겠지.","JPN":"おそらく次の犯行が深夜の殺人鬼の最後の殺人となるだろう。","ENG":"I believe that the next murder will be the Midnight Killer's last.","TWN":"也許下一次犯罪就是午夜殺人魔最後一次行兇了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"네에……? 대체 어떻게……?","JPN":"ええっ……？　いったいどうやって……？","ENG":"What...? When did you...?","TWN":"啊……？這到底是怎麼回事……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 심야의 살인마의 정체 역시 누구인지 대충 감이 와.","JPN":"それに、深夜の殺人鬼の正体も、また誰なのかだいたい予想がつく。","ENG":"Also, I have a guess as to whom the Midnight Killer might actually be.","TWN":"並且，我也猜到了午夜殺人魔的大概身份。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마의 정체를 알아냈다고요……!?","JPN":"深夜の殺人鬼の正体がわかったんですか……！？","ENG":"You're saying that you know who the Midnight Killer is...?!","TWN":"你說你知道了午夜殺人魔的真實身份……？！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 이러고 있을 필요가 없잖아요. 어서 범인을……!","JPN":"じゃあ、こんなことしてる必要なんてないですよね？　早く犯人を……！","ENG":"Then, what are you doing here? We must find the culprit–!","TWN":"那樣的話，就沒必要在這裡浪費時間了。快點抓住犯人……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그게 그렇게 쉽지는 않을 걸세.","JPN":"いや、そう簡単には行かないはずだ。","ENG":"No. It won't be that easy.","TWN":"不，不會那麼簡單的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 사건에서 범인의 신원을 특정하는 건 큰 의미가 없거든.","JPN":"この事件で犯人の身元を特定したとしても、大した意味を成さないんだ。","ENG":"For this case, identifying the killer is of little significance.","TWN":"在這起事件中，犯人的身份並沒有太大意義。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면 이 사건에는 내 오랜 숙적이 관여하고 있으니까 말이지.","JPN":"なぜなら、この事件には私の古い宿敵が関与しているからな。","ENG":"Because my old nemesis seems to be involved in this case.","TWN":"這裡面還涉及到我的一個老對手。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"숙적이라고요?","JPN":"宿敵？","ENG":"Your nemesis?","TWN":"老對手？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 <color=#ffd34c>모리어티</color> 교수에 대해 들어본 적이 없나?","JPN":"君は<color=#ffd34c>モリアーティ</color>教授について聞いたことがあるか？","ENG":"Have you ever heard of Professor <color=#ffd34c>Moriarty</color>?","TWN":"你有聽說過<color=#ffd34c>莫里蒂</color>教授嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"전혀요. 누군데요, 그 사람이?","JPN":"いいえ、全然。誰ですか、その人は？","ENG":"Not at all. Who is he?","TWN":"沒有……那個人是誰？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그는 범죄계의 나폴레옹 같은 존재라네.","JPN":"彼は犯罪界のナポレオンのような存在だ。","ENG":"He is like the Napoleon of the criminal world.","TWN":"他就像是犯罪界的拿破崙。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"런던에서 벌어진 사건의 절반, 그리고 밝혀지지 않은 모든 범죄는 그에게 책임이 있지.","JPN":"ロンドンで発生した事件の半分、そして明らかになっていないすべての犯罪は彼に責任がある。","ENG":"He is responsible for half of the cases that happened in London, and all of the undisclosed cases.","TWN":"倫敦發生的一半事件，以及所有未被揭露的犯罪，恐怕都要算在他的頭上。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 자신은 직접 나서지 않으면서, 범죄자에게 필요한 도움과 자문을 주거든.","JPN":"自身は直接表に出ないが、犯罪者に必要な手助けやアドバイスを提供している。","ENG":"He doesn't take action himself, and acts as a consultant to criminals.","TWN":"他本人並不直接出面，卻為犯罪者提供所需的幫助和諮詢。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 수년 전에는 그림자 사태…….","JPN":"そう、数年前のシャドウ事変や……","ENG":"Yes, the Shadow incident that happened a few years ago...","TWN":"是，幾年前的暗影事件……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 이번 심야의 살인마 사건 역시 그 배후에는 모리어티 교수가 있었어.","JPN":"そして今回の深夜の殺人鬼事件もまた、その裏にモリアーティ教授がいた。","ENG":"As well as the Midnight Killer case. Professor Moriarty was the one behind them all.","TWN":"還有這次的午夜殺人魔事件，幕後黑手都是他。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"보름 전. 나는 교수를 직접 마주하고 모든 사태의 배후에 그가 있다는 걸 깨달았지.","JPN":"半月前。私は直接教授と対峙しすべての事態の裏に彼がいるということに気付いた。","ENG":"Two weeks ago, I met with him and realized that he was behind it all.","TWN":"半個月前，我親自面對教授，意識到他是這次事件的幕後黑手。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그의 뒤를 캐서, 현재 어느 종교 집단에 소속해 있다는 걸 알게 됐어.","JPN":"そして彼を調査し、現在、とある宗教集団に所属しているということを知ったのだ。","ENG":"So I did some digging around, and discovered that he is a member of some religious group.","TWN":"在追查他的行蹤時，發現他現在隸屬於某個宗教團體。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 종교 집단이 바로 황금 새벽회였다네.","JPN":"その宗教集団こそ、まさに黄金の暁団だ。","ENG":"And that group is the Golden Dawn.","TWN":"那個宗教團體就是黃金黎明會。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"황금 새벽회라고요?","JPN":"黄金の暁団？","ENG":"The Golden Dawn?","TWN":"黃金黎明會嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"알고 있어요. 그들은 마석을 제조해서 수많은 신도들을 끌어들이고 있었어요.","JPN":"知ってます。彼らは魔石を作って多くの信徒を集めてました。","ENG":"I know them. They are gathering hundreds of followers with their Mana Stones manufacturing.","TWN":"我知道。他們通過製造魔石吸引了大量信徒。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"조사 결과, 그들의 근거지와 세력, 교리와 행동 강령…….","JPN":"調査の結果、彼らの本拠地と勢力、教理と行動規範……","ENG":"With my investigation, I was able to figure out their location, the number of members, their doctrine…","TWN":"我根據調查，掌握了他們的據點位置、勢力大小、教義、行動綱領……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그들이 어떻게 마석을 제조하여, 런던에 유통할 수 있었는지 파악할 수 있었네.","JPN":"そして彼らがどうやって魔石を作り、ロンドン内に流通することができたのかも把握できた。","ENG":"as well as their method of manufacturing and distribution of Mana Stones.","TWN":"還有他們魔石的製造方法和在倫敦的流通手段。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 그동안 모습을 보이지 않던 이유가…….","JPN":"じゃあ、しばらく姿を消してた理由って……","ENG":"So, that's why I haven't seen you all this time...","TWN":"所以你這段時間沒再露面……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 내가 자리를 비운 틈을 타, 교수가 먼저 손을 쓴 모양이더군.","JPN":"だが私が留守になっている間、教授が先手を打ったらしい。","ENG":"However, it seems that the Professor took the initiative while I was away.","TWN":"但是趁我不在的時候，教授先下手了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"런던 각지에 숨어있는 사교도들을 교묘하게 이용하여, 시민들을 혼란에 빠트렸으니까.","JPN":"ロンドン各地に潜む邪教徒を巧妙に利用し、市民を混乱に陥れたのだ。","ENG":"Cleverly using the cultists hidden all throughout London, he's putting the citizen in confusion.","TWN":"他巧妙地利用了藏在倫敦各地的邪教徒，使市民陷入了混亂。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 결과, 자네를 위험에 노출시키고 말았지.","JPN":"その結果、君を危険に晒してしまった。","ENG":"As a result, you were exposed to the dangers.","TWN":"結果是，讓你陷入了危險之中。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이거 면목이 없군, 사과하지.","JPN":"面目ない、すまなかった。","ENG":"I don't know what to say, but I'm sorry.","TWN":"真是丟人，抱歉。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 사건에서 가장 중요한 건, 심야의 살인마의 정체가 아니야.","JPN":"この事件でもっとも大事なのは、深夜の殺人鬼の正体ではない。","ENG":"The most important part of this case isn't who the Midnight Killer is.","TWN":"那麼回到剛才，在這起事件中最重要的不是午夜殺人魔的身份。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그보다 중요한 것은 그들의 의식을 저지하는 거지.","JPN":"それより大事なのは彼らの儀式を阻止することだ。","ENG":"It's that we prevent them from finishing their ritual.","TWN":"更重要的是阻止他們的儀式。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"전에 말씀하신 <color=#ffd34c>무언가</color>를 이 세계로 불러내는 의식이로군요.","JPN":"前に話してた<color=#ffd34c>何か</color>をこの世界に呼び出す儀式のことですね。","ENG":"This must be the ritual to summon <color=#ffd34c>something</color> into this world you mentioned before.","TWN":"是之前提到的把<color=#ffd34c>某種東西</color>召喚到我們世界的儀式嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 늦었지만 믿어주니 고맙군.","JPN":"はは、遅かれ信じてくれて、ありがとう。","ENG":"Haha, I'm grateful to you for trusting me after all.","TWN":"哈哈，雖然有點晚了，但還是謝謝你的信任。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래. 우리는 심야의 살인마보다 한발 앞서 그 타겟을 찾아내서 보호해야만 해.","JPN":"ああ。私たちは深夜の殺人鬼より一歩先にそのターゲットを探して保護しなければならないのだ。","ENG":"Correct. We must find and protect the Killer's target before he gets to her first.","TWN":"對，我們必須比午夜殺人魔更早一步找到並保護那個目標。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 사건이 어떤 기묘한 현상이나, 불가사의한 것이 아닌.","JPN":"この事件が奇妙な現象、または不可思議なことで片付けるのではなく。","ENG":"This case is not some strange or mysterious phenomenon.","TWN":"這起事件並不是某種靈異事件或者神秘現象。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이성으로 납득할 수 있고, 해결 가능한 <color=#ffd34c>인간의 소행</color>이라는 걸 대중들에게 공표하고 증명하는 거야.","JPN":"理性的に納得がいき、解決できる<color=#ffd34c>人間の所業</color>だということを大衆に公表して証明するのだ。","ENG":"It can be solved with reason, and prove to the public that <color=#ffd34c>a human is behind it</color>.","TWN":"要向大眾公佈並證明這是<color=#ffd34c>人類所為</color>，是可以用理性理解和解決的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래야 심야의 살인마라는 부정적 상징으로 결집된 집단 무의식이 구심점을 잃게 되고.","JPN":"そうすれば、深夜の殺人鬼という否定的な象徴で結集した集合的無意識が中心を失い。","ENG":"This will make the collective unconsciousness, united by the negative symbol known as the Midnight Killer lose its pivot.","TWN":"這樣一來，圍繞午夜殺人魔這個負面象徵形成的集體無意識就會失去中心。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 녀석들의 의식은 실패로 돌아가겠지.","JPN":"結局、やつらの儀式は失敗に終わるだろう。","ENG":"In the end, their ritual will fail.","TWN":"最終，他們的儀式會以失敗告終。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 소리인지 잘은 모르겠지만.","JPN":"詳しいことはまだいまいちですか……","ENG":"I'm not sure if I fully understand, but.","TWN":"雖然不太明白你在說什麼。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무튼 다음 희생자를 먼저 찾아내기만 하면 된다는 거죠?","JPN":"とにかく、先に次の犠牲者を見つければいいんですよね？","ENG":"All we have to do is find the next victim first, right?","TWN":"總之，只要先找到下一個犧牲者就行了，對吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다음 희생자는 심장. 즉, <color=#ffd34c>흉부</color>에 증표가 있는 이능력자라네.","JPN":"次の犠牲者は心臓。つまり、<color=#ffd34c>胸部</color>に印がある異能力者だ。","ENG":"The next victim will be the heart. In other words, a Supernatural with a mark on her <color=#ffd34c>chest</color>.","TWN":"下一個犧牲者是心臟。也就是說，<color=#ffd34c>胸部</color>有標記的超能力者。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이것만으로는 정보가 부족해.","JPN":"だが、これだけでは情報が足りない。","ENG":"However, this information alone is insufficient.","TWN":"不過光是這樣資訊不足。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스코틀랜드 야드가 최선을 다해주고 있지만, 아마 때를 맞추기 어려울 거야.","JPN":"スコットランドヤードが頑張ってくれているが、たぶん間に合わないだろう。","ENG":"Scotland Yard will do their best, but it will be difficult to get the timing right.","TWN":"蘇格蘭場正在盡全力，但可能很難趕上時間。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이능력자들은 정부를 불신하고 있으니까, 그들의 자발적인 협력을 바라기도 어려워.","JPN":"異能力者は政府を信頼していないから、彼らの自発的な協力を望むこともできない。","ENG":"The Supernaturals distrust the government, so expecting any voluntary cooperation will be difficult.","TWN":"這些超能力者對政府不信任，所以沒法指望他們自願合作。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 가장 빠른 방법은 황금 새벽회에 직접 잠입하여 신도 명단을 손에 넣는 거지.","JPN":"やはりもっとも早い方法は黄金の暁団に直接潜入し、信徒のリストを手に入れることだ。","ENG":"The fastest way would be to infiltrate the Golden Dawn and obtain the list of their members.","TWN":"果然最快的方法就是直接潛入黃金黎明會，拿到信徒名單。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그건 상당한 리스크가 동반돼.","JPN":"だが、それは相当リスクが高い。","ENG":"But that also comes with considerable risk.","TWN":"但那伴隨著相當大的風險。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이건, 사진……? 지금 이걸 돌려주겠다고요?","JPN":"これは、写真……？　これを今、返してくれるってことですか？","ENG":"It's my photo...? You're giving it back to me at this moment?","TWN":"這是，照片……？現在要把這個還給我嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래. 자네는 이쯤에서 빠지고, 사건이 끝날 때까지 이곳에 머물도록 해.","JPN":"そうだ。君はこの辺で抜けて、事件が終わるまでここに泊まるといい。","ENG":"Yes. You've done your job, so stay here until the case is over.","TWN":"沒錯。你已經做得很好了，現在就待在這裡，直到事情結束吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이건 내 업이라네. 이제부터 이 사건은 나 혼자 조사하도록 하지.","JPN":"これは私の仕事だ。これからこの事件は私一人で調査する。","ENG":"This is my job. I'll investigate this case on my own from here on out.","TWN":"這是我的職責。從現在開始，這個案件由我一個人來調查。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지! 웃기지 말라고요!","JPN":"もう！　ふざけないでください！","ENG":"Ugh! You've got to be joking me!","TWN":"呃！別開——這種玩笑了！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……스완?","JPN":"……スワン？","ENG":"...Swan?","TWN":"……史旺？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 어디까지 절 얕보고 있는 거죠?","JPN":"どこまで私のことを見くびったら気が済むんですか？","ENG":"How much more are you going to underestimate me?","TWN":"你到底要小瞧我到什麼程度？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이런 식으로 사진을 받아낸다고 제가 기뻐할 줄 알았나요?","JPN":"こんなふうに写真を取り戻せたからって、私が喜ぶとでも思ったんですか？","ENG":"Did you think I'd be thrilled to get the photo back this way?","TWN":"你以為這樣拿到照片，我就會開心嗎！？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그들은 저에게 무대를 빼앗아 갔어요. 프리마돈나로서 이걸 그냥 보고만 있을 것 같나요?","JPN":"彼らは私から舞台を奪ったんです。プリマドンナとしてこれを黙って見ていられるわけないでしょう？","ENG":"They stole my stage from me. Do you think I, as the prima donna, will just stand back and watch?","TWN":"他們奪走了我的舞台。你覺得作為首席女主角的我就該坐視不理？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"다시 설 무대를 되찾을 때까지 전 포기하지 않을 거예요.","JPN":"再び立つ舞台を取り戻すまで、私は諦めません。","ENG":"Until I can get back on stage, I won't give up.","TWN":"在可以重新站上舞台之前，我絕不會放棄。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"오직 그것만이 지금껏 성원을 보내준 팬들에게 보답하는 방법이겠죠.","JPN":"ただそれだけが今まで応援してくれたファンの期待に応える方法なんですから。","ENG":"This is the only way of repaying my fans who have supported me so far.","TWN":"只有這樣，才能報答一直以來支持我的粉絲們。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 그 사진은 모든 게 끝날 때까지 넣어두세요, 애버라인.","JPN":"だからその写真はすべてが終わるまで仕舞ってください、アバーライン。","ENG":"So, keep the photo until all of this is done, Abberline.","TWN":"所以那張照片請先收起來，艾伯林。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이제 이건 당신 혼자만의 사건이 아니니까.","JPN":"もうこれはあなた一人だけの事件じゃないんですから。","ENG":"Because now, this isn't just your case.","TWN":"這已經不只是你一個人的案子了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤.","JPN":"一週間後","ENG":"A week later.","TWN":"一周後。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 25일 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원","JPN":"1888年10月25日　ロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院","ENG":"October 25, 1888, London, <color=#ffd34c>Golden Dawn</color> Underground Temple","TWN":"1888年10月25日 倫敦，<color=#ffd34c>黃金黎明會</color>地下神廟"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 결국 돌아오실 줄 알고 있었답니다. 자매님.","JPN":"マグヌム・オプス。また戻ってこられると思っていました。シスター。","ENG":"Magnum Opus. I knew you'd return, sister.","TWN":"偉大傑作在上。我就知道你最終會回來的，姐妹。"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"정말 입회만 해도, 마석을 얻을 수 있는 거죠?","JPN":"本当に入会しただけで、魔石を得られるんですよね？","ENG":"Do I really get Mana Stones for just joining?","TWN":"真的只要加入，就能獲得魔石嗎？"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"물론이죠.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然了。"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"자, 그럼 이쪽으로.","JPN":"さあ、こちらへ。","ENG":"Now, come this way, please.","TWN":"那麼，請來這邊。"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"첩보에 따르면, 그들은 새로운 신도를 받기 전에 어떤 의식에 동참시킨다고 해.","JPN":"諜報によると、彼らは新しい信徒を受け入れる前にとある儀式に参加させるらしい。","ENG":"According to intelligence, they make new recruits participate in a ritual before accepting them.","TWN":"根據情報，他們在接納新信徒之前會進行某種儀式。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리 계획은 그 순간을 노려, 그들을 검거하고 신도 명단을 손에 넣는 거지.","JPN":"私たちの計画はその瞬間を狙い、彼らを検挙して信徒のリストを手に入れることだ。","ENG":"Our plan is to wait for that moment, arrest them, and get our hands on the list.","TWN":"我們的計畫是抓住那個時機，逮捕他們並獲取信徒名單。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"의식에 동참시킨다고요? 어떤 의식이죠?","JPN":"儀式に参加させる？　いったいどんな儀式なんですか？","ENG":"Participate in a ritual? What kind of ritual is it?","TWN":"參與儀式？什麼儀式？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>마그눔 오푸스</color>. 이른 바, 마석을 만들어내는 공정이라네.","JPN":"<color=#ffd34c>マグヌム・オプス</color>。いわゆる、魔石を作り出す工程だそうだ。","ENG":"<color=#ffd34c>Magnum Opus</color>. It is their process of creating Mana Stones, so to speak.","TWN":"<color=#ffd34c>偉大傑作</color>。所謂的，就是製造魔石的工藝。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"음? 방금 그 말, 들은 기억이 있어요.","JPN":"うん？　その言葉、聞き覚えがあります。","ENG":"Hmm? I remember hearing that word.","TWN":"嗯？剛才那句話，我記得聽過。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 마석을 연성하는 연금술. 그 과정은 니그레도, 알베도, 루베도…….","JPN":"マグヌム・オプス。魔石を錬成する錬金術。その過程はニグレド、アルベド、ルベド……","ENG":"Magnum Opus. The alchemy of transmuting Mana Stones. The process is Nigredo, Albedo, and Rubedo...","TWN":"偉大傑作。煉成魔石的煉金術。其過程為黑化、白化、紅化……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이게 뭘 뜻하는지는 잘 모르겠지만요.","JPN":"これが何を意味してるのかはよくわからないですけど。","ENG":"I'm not sure what those mean, however.","TWN":"雖然我不知道這是什麼意思。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스는 최후의 <color=#ffd34c>걸작</color>이라는 의미라네.","JPN":"マグヌム・オプスは最後の<color=#ffd34c>傑作</color>という意味だ。","ENG":"Magnum Opus means the last <color=#ffd34c>great work</color>.","TWN":"這個詞的意思是最終的<color=#ffd34c>傑作</color>。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"연금술에서는 황금을 제조하는 모든 공정을 뜻하기도 하고.","JPN":"錬金術では黄金を作り出す、すべての工程のことを指す。","ENG":"In alchemy, it used to mean the entire process of transmuting metal into gold.","TWN":"在煉金術中，它也指製造黃金的整個過程。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한편으로는 인간의 영혼을 불멸의 존재로 바꾸는 기술을 뜻하기도 해.","JPN":"一方、人間の魂を不滅の存在に変える技術を指したりもする。","ENG":"On the other hand, it also refers to the technology of turning a human's soul into an immortal being.","TWN":"另一方面，也意指將人類的靈魂轉變為不朽存在的技術。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"인간의 영혼을 불멸하게 만든다고요?","JPN":"人間の魂を不滅に？","ENG":"Turn a human soul immortal?","TWN":"你說讓人類的靈魂變得不朽？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그들이 벌이고 있는 의식의 실체는 연금술과는 거리가 멀지.","JPN":"だが、彼らが行っている儀式の実体は錬金術とはまったく違う。","ENG":"But the ritual they are doing is far from alchemy.","TWN":"但是他們正在進行的儀式，和煉金術可沒什麼關係。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그저 이 세계의 추악한 진실을 악용하고 있을 뿐이니까.","JPN":"ただこの世界の醜悪な真実を悪用しているだけだからな。","ENG":"They are merely exploiting the ugly truth of this world.","TWN":"只是利用這個世界的醜惡真相而已。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_MAN","text":{"KOREA":"오셨습니까, 필로소푸스.","JPN":"お帰りなさい、フィロソプス。","ENG":"You have come, Philosophus.","TWN":"你來了，哲學家。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_MAN","text":{"KOREA":"마그눔 오푸스. 새로운 자매님도 함께 오셨군요.","JPN":"マグヌム・オプス。新しいシスターも一緒なんですね。","ENG":"Magnum Opus. And with you a new sister.","TWN":"偉大傑作在上。新的修女也一起來了啊。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"잠깐, 저 뒤에 사람들은 왜 묶여있죠?","JPN":"ちょっと、あの後ろの人たちはどうして縛られてるんですか？","ENG":"Wait, why are the people behind you tied up?","TWN":"等一下，後面那些人為什麼被綁著？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"무슨 벌을 받고 있는 건가요? 초췌한 걸 보면 며칠은 굶은 것 같은데…….","JPN":"何かの罰ですか？　数日は何も食べてないような痩せ姿なんですけど……","ENG":"What's going on here? They look haggard as if they haven't eaten for a while...","TWN":"他們在受什麼懲罰嗎？看起來很憔悴，像是餓了好幾天……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"신경 쓰실 것 없답니다. 저건 니그레도. 흑화의 과정.","JPN":"お気になさらずに。あれはニグレド。黒化する過程。","ENG":"No need to worry about that. That is Nigredo. The process of blackening.","TWN":"不用在意，那是尼格列多。黑化的過程。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"무가치한 존재를 유의미한 존재로 탈바꿈하는 첫번째 공정이니까요.","JPN":"無価値な存在を意味のある存在に生まれ変わらせる最初の工程なんです。","ENG":"It is the first process to undergo a transformation from unworthiness to meaningfulness.","TWN":"這是將無價值的存在轉變為有意義存在的第一道工序。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"공정이라고요……?","JPN":"工程ですって……？","ENG":"Process...?","TWN":"工序……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"먼저, 그들은 런던 빈민가에서 사람을 납치하여 사원 어딘가에 감금하지.","JPN":"まず、彼らはロンドンのスラム街で人をさらい、寺院のどこかに監禁する。","ENG":"First, they kidnap people from the London slums and imprison them somewhere in the temple.","TWN":"首先，他們會在倫敦的貧民區實行綁架，然後把擄來的貧民關押在修道院的某個地方。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네 말대로, 이 도시에서 빈민 몇 명쯤 실종된다고 해도 크게 문제되지는 않을 테니까.","JPN":"君が言ったとおり、この都市で貧民が何人か失踪したって大して問題にならないはずだからな。","ENG":"Like you said, it isn't a big problem for the city if a few people from the slums go missing.","TWN":"正如你所說，在這座城市裡，即使有幾個貧民失蹤了，也不會引起太大的問題。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"황금 새벽회의 사원은 런던에서 가장 안개가 짙게 깔리는 강변에 있지.","JPN":"黄金の暁団の寺院は、ロンドンでもっとも霧が濃い川辺にある。","ENG":"The Golden Dawn's temple is located near the river where the fog is thickest in all of London.","TWN":"黃金黎明會的據點位於倫敦濃霧最深的河邊。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그들은 납치한 빈민들을 안개에 노출시킨 채, 자지도, 먹지도 못하게 한다네.","JPN":"彼らは拉致した貧民たちを霧に晒して、寝ることも、食べることも禁ずる。","ENG":"They expose the kidnapped people to the fog and do not allow them to eat or sleep.","TWN":"他們將綁架來的貧民暴露在霧中，不讓他們睡覺，也不給他們吃的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 극한 상황에 놓인 인간이 장시간 안개에 노출되면 어떻게 변하는 줄 아나?","JPN":"そんな極限の状況に置かれた人間が長時間霧に晒されるとどうなるか、知っているか？","ENG":"Do you know what happens to people who have been exposed to the fog for too long in such an extreme situation?","TWN":"你知道長時間暴露在霧中的人在極端情況下會變成什麼樣子嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"침식병으로 신체가 시커멓게 변하고, 끝내 마물이 된다네.","JPN":"侵食病で体が真っ黒になり、結局は魔物になる。","ENG":"The Corruption Syndrome turns their bodies black, and eventually become monsters.","TWN":"被侵蝕病感染後，身體會變得漆黑，最終變成怪物。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"몸이 검게 변해서 마물이 된다고요?","JPN":"体が黒くなって魔物になる？","ENG":"Their bodies turn black, then they turn into monsters?","TWN":"身體變黑，變成怪物？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"That can't be...","TWN":"不會吧……？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 그들은 그걸 <color=#ffd34c>니그레도</color>. 흑화 과정이라고 불러.","JPN":"そう、彼らはこれを<color=#ffd34c>ニグレド</color>。黒化過程と呼んでいる。","ENG":"Yes. To them, this is <color=#ffd34c>Nigredo</color>. The process of blackening.","TWN":"是的，他們稱之為<color=#ffd34c>尼格列多</color>，也就是黑化過程……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 말해, 인간을 마물로 바꾸고 다시 그 마물로부터 마석을 채취하고 있는 거야.","JPN":"つまり、人間を魔物に変えて、またその魔物から魔石を採取しているのだ。","ENG":"In other words, they turn humans into monsters and harvest Mana Stones from them.","TWN":"實質上就是將人類變成怪物，然後從這些怪物身上採集魔石的第一步。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이것이 그들이 말하는 <color=#ffd34c>연금술</color>의 실체지.","JPN":"これが彼らが言う<color=#ffd34c>錬金術</color>の実体さ。","ENG":"This is the reality of their so-called <color=#ffd34c>alchemy</color>.","TWN":"這就是他們所說的<color=#ffd34c>煉金術</color>的真相。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"이곳은 <color=#ffd34c>알베도</color>의 방.","JPN":"ここは<color=#ffd34c>アルベド</color>の部屋。","ENG":"This place is the room of <color=#ffd34c>Alebdo</color>.","TWN":"這裡是<color=#ffd34c>艾爾貝多</color>的房間。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"여기서는 모든 죄를 뒤집어쓰고 검게 변한 니그레도를 정화하는 과정을 거친답니다.","JPN":"ここではすべての罪を浴びて黒化したニグレドを浄化します。","ENG":"Here, we purify all the Nigredos that have turned black with sin.","TWN":"在這裡，會經歷一個淨化過程，將所有因背負著罪孽而變得漆黑的尼格列多淨化。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"이를 통해, 그들의 영혼은 신과 하나 되어, 불멸의 원석.","JPN":"これを通じて彼らの魂は神と同化し、不滅の原石。","ENG":"Through this, their soul will merge as one with god, becoming an immortal gemstone.","TWN":"通過這個，他們的靈魂與神合為一體，成為不朽的原石。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>루베도</color>에 다다르게 되는 거죠.","JPN":"<color=#ffd34c>ルベド</color>にたどり着くのです。","ENG":"Thus, reaching <color=#ffd34c>Rubedo</color>.","TWN":"之後，<color=#ffd34c>露貝多</color>就要達成了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그, 그렇군요…….","JPN":"そ、そうなんですね……","ENG":"I-I see...","TWN":"啊，是、是……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐만요, 뭔가 이상하잖아요!","JPN":"ちょっと、おかしくないですか！","ENG":"Hold on, something doesn't sound right!","TWN":"等一下，感覺有點不太對勁啊！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이능력자도 아닌, 평범한 인간이 안개 좀 쐬었다고 마물이 된다고요?","JPN":"異能力者でもない、普通の人間が霧にちょっと露出されただけで魔物になるんですか？","ENG":"Even ordinary humans who are not Supernaturals become monsters when exposed to the fog?","TWN":"除了超能力者，普通人吸了霧氣也會變成怪物嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마물이 되는 게 이능력자뿐이라는 인식은 런던 그림자 사태로 인한 오해야.","JPN":"魔物になるのが異能力者だけだとういう認識は、ロンドンのシャドウ事変から生じた誤解だ。","ENG":"The misconception that only Supernaturals become monsters is a misunderstanding due to London's Shadow incident.","TWN":"認為只有超能力者會變成怪物的看法，是倫敦陰影事件引起的誤會。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"애초에 자네는 왕국 밖의 마물들이 대체 어디서 나타난다고 생각하나?","JPN":"そもそも君は王国の外にいる魔物がいったいどこから現われていると思っているのだ？","ENG":"Where do you think the monsters outside the kingdom come from in the first place?","TWN":"你認為王國外的怪物到底是從哪裡出現的呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"국경지대에서 군인들은 무엇을 상대하고 있지?","JPN":"国境地帯で軍人は何を相手している？","ENG":"What do you think our soldiers are fighting against at the border?","TWN":"邊境地區的士兵們在對付什麼？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면, 마물의 정체가 실은……!","JPN":"ということは、魔物の正体って……！","ENG":"Then, the monsters are actually...!","TWN":"那麼，怪物的真面目其實是……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"십수 년 전, 마석이 발견된 뒤로, 이 세계는 조금씩 안개에 의해 침식되기 시작했어.","JPN":"十数年前に魔石が発見されて以来、この世界は少しずつ霧によって侵食され始めた。","ENG":"Decades ago, after the discovery of the Mana Stones, the world began to slowly become corrupted by the fog.","TWN":"十幾年前，自從發現了魔石，這個世界就開始逐漸被迷霧侵蝕。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러더니 이 도시는 이제 낮에도 태양을 볼 수 없는 지경에 이르렀지.","JPN":"今に至っては、この都市はもう昼間も太陽を見ることができなくなった。","ENG":"It has come to the point where the sun cannot be seen during the day in the city.","TWN":"到現在，這座城市即使在白天也看不到太陽了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금은 인체에 유해한 수준이지만, 안개가 더 짙어지면 곳곳에서 문제가 터질 거야.","JPN":"今のところは人体に有害な程度で済むんだが、これ以上霧が濃くなると各地で問題が相次ぐだろう。","ENG":"Even now, the fog is harmful to humans. But if it gets any thicker, it will cause more problems.","TWN":"現在只是對人體有害的程度，但如果霧氣變得更濃，就會出現各種問題了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"런던의 시민들이 왜 별것도 아닌 이유로, 서로를 증오하게 되었는지 생각해 본 적 있나?","JPN":"ロンドンの市民がどうして些細な理由でお互い憎むようになったか、考えてみたことはあるか？","ENG":"Have you ever thought why the people of London started hating each other for seemingly trivial reasons?","TWN":"你有沒有想過，倫敦的市民為什麼會因為一些無關緊要的理由而互相憎恨？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"평범한 인간이든, 이능력자든 하물며 나나 자네도 예외는 없어.","JPN":"普通の人間でも異能力者でも、なんなら私も君も、例外ではない。","ENG":"Ordinary humans and Supernaturals alike, even you and I are not the exception.","TWN":"無論是普通人，還是超能力者，甚至是你我也不例外。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"광기의 안개에 노출된 인간은 이성을 잃고, 서서히 마물이 되어갈 뿐이라네.","JPN":"狂気の霧に晒された人間は理性を失い、徐々に魔物になっていくだけさ。","ENG":"Humans exposed to the fog's madness lose rationality, and gradually transform into monsters.","TWN":"暴露在迷霧中的人類會失去理智，逐漸變成怪物。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이런 상황에서 녀석들의 만행을 외면하면 외면할수록 그 임계치는 점점 높아지겠지.","JPN":"このような状況でやつらの蛮行から目を背けば、その臨界値はどんどん高くなるだろう。","ENG":"If we continue to turn a blind eye to their atrocities, it will only get closer to the critical point.","TWN":"這種情況下，越是無視那些傢伙的暴行，就會越快地臨近那個臨界點。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"종극에는 이 세계의 모든 것이 안개에 뒤덮여 삼켜지게 될 거야.","JPN":"最後にはこの世界のすべてが霧に飲み込まれることになる。","ENG":"In the end, the fog will consume everything in this world.","TWN":"最終，這個世界的一切都會被霧氣吞噬。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 이걸로 모든 입회 과정이 끝났습니다.","JPN":"マグヌム・オプス。これですべての入会過程が終わりました。","ENG":"Magnum Opus. With this, all the induction process is complete.","TWN":"偉大傑作在上。至此，所有的入會過程都結束了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그, 그럼 이제 마석을 받을 수 있는 건가요……?","JPN":"じゃ、じゃあ、これで魔石をもらえるんですか……？","ENG":"Th-then, can I now get Mana Stones...?","TWN":"那、那麼現在可以領取魔石了嗎……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"물론이죠. 대신 오늘 본 것은 절대 외부에 발설하시면 안 됩니다.","JPN":"もちろんです。その代わり、外で今日見たことは、絶対口に出してはいけません。","ENG":"Of course. Instead, you must never disclose what you saw today to others.","TWN":"當然可以。不過今天看到的事情絕對不能對外洩露。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이, 이런 걸 어떻게 말하겠어요!","JPN":"そ、そんなこと言えるわけないじゃないですか！","ENG":"W-why would I want to do that?","TWN":"這、這種事我怎麼說得出口啊！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"자, 그럼 이제 이 명부를 작성해주세요.","JPN":"さて、それではこの名簿を作成してください。","ENG":"Now, please fill out this list.","TWN":"那麼，請填寫這份名單吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"자매님과 마석을 사용할 아이의 이름과 탄생일을 기재해 주시면 됩니다.","JPN":"シスターと、魔石を使用する子どもの名前、そして誕生日を記入してください。","ENG":"Write down your name and the name and birthday of the child who will use the Mana Stones, sister.","TWN":"請寫上姐妹以及孩子的名字和出生日期。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"아이의 탄생일?","JPN":"子どもの誕生日？","ENG":"The child's birthday?","TWN":"出身日期？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이상하네요. 탄생일 같은 게 왜 필요하죠?","JPN":"気になりますね。どうして誕生日なんかが必要なんですか？","ENG":"That's strange. Why write down birthdays?","TWN":"真奇怪。為什麼需要生日這種東西呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"그야, 숫자는 예로부터 신비로운 힘을 가지고 있으니까요.","JPN":"数字は昔から神秘的な力を持っています。","ENG":"That is because numbers have had mystical powers since ancient times.","TWN":"因為，數字自古以來就擁有神秘的力量。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"신도들의 별자리를 파악하는 것만으로도, 생각보다 많은 것을 점지할 수 있답니다.","JPN":"そのため、信徒の星座を把握するだけでも、意外と多くのことがわかるのです。","ENG":"By just understanding the constellation of our followers, we are able to predict things more than we think.","TWN":"僅僅通過了解信徒們的星座，就能預見到比想像中更多的事情。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"자매님? 혹시 아직 입회를 망설이고 계신가요?","JPN":"シスター？　もしかして、まだ入会をためらっているのですか？","ENG":"Sister? Are you hesitating to join?","TWN":"姐妹？你還在猶豫是否入會嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"조금만 더…… 고민할 시간을 가져도 괜찮을까요?","JPN":"もう少し……考える時間がほしいです。","ENG":"Will it be okay... if I thought about this a little longer?","TWN":"要不我再稍微考慮一下吧……可以嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"저는 아직 제 신앙을……. 그 아이를…….","JPN":"私はまだ自分の信仰を……あの子を……","ENG":"I still have my faith... and the child…","TWN":"我依然對我的信仰……還有那個孩子……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 얼마든지요. 어차피 구원의 길은…….","JPN":"マグヌム・オプス。どうぞ。どうせ救いの道は……","ENG":"Magnum Opus. Take your time. For the path to salvation is–","TWN":"偉大傑作在上。請便吧。反正救贖之路就只有……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"아니, 그렇게는 안 되겠네.","JPN":"いや、そうはできない。","ENG":"No, that will not be allowed.","TWN":"不，那樣不行。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"슬슬 내 뒤를 캐고 있던 그 남자가 움직일 타이밍이라고 생각했는데.","JPN":"そろそろ私のことを嗅ぎまわっていたあの男が動く時だと思っていたのだが。","ENG":"I figured it was about time for the man who has been investigating me to make a move.","TWN":"我覺得那個一直在調查我的傢伙差不多該行動了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"의외로군. 그 남자가 직접 움직이지 않고 대리인을 보낼 줄이야.","JPN":"意外だな。あの男が直接動くわけではなく、代理人を送るとは。","ENG":"But this is unexpected. I thought he would come himself and not send a proxy.","TWN":"真意外啊。沒想到他不親自出馬，而是派了你。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_NULL","text":{"KOREA":"마, 마기스텔 템프리께서 여긴 어쩐 일로……?","JPN":"ま、マギステル・テンプリ様が、なぜここに……？","ENG":"M-Magister Templi... What brings you here...?","TWN":"神、神殿主大人，你怎麼會在這裡……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 연기는 훌륭했지만, 런던에서 발생하는 모든 정보는 내 손아귀 안에 있다네.","JPN":"君の演技は素晴らしかったが、ロンドンで発生しているすべての情報は私の手の内にあるのだ。","ENG":"I applaud your acting, but all the information about what happens in London is in the palm of my hand.","TWN":"你的演技很出色，但倫敦發生的所有資訊都在我的掌握之中。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"예를 들면, 자네가 사칭하고 있는 그 교회는 이제 런던 지도에 존재하지 않거든.","JPN":"例えば、君が名乗ったその教会は、もうロンドンの地図には存在しない。","ENG":"For instance, the church you are impersonating no longer exists on the London map.","TWN":"比如，你冒充的那座教堂現在已經不在倫敦的地圖上了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"며칠 전에 폭동에 휘말려 붕괴되어 버렸으니까.","JPN":"数日前に暴動に巻き込まれて崩壊してしまったんだ。","ENG":"It collapsed after being caught up in a riot a few days ago.","TWN":"因為幾天前它就在暴動中被摧毀了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 자네는 누구일까?","JPN":"だとすれば、君は誰なのか？","ENG":"So, who are you?","TWN":"那麼你是誰呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"지금 내가 생각하고 있는 그 여배우가 맞을까?","JPN":"今、私が考えているあの女優で合っているのか？","ENG":"Are you the actress that comes to my mind right away?","TWN":"是我現在想的那個女演員對嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"……큭!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"이거 무척이나 궁금하군. 그 남자에게 있어, 자네는 대체 어떤 의미지?","JPN":"これはとても興味深い。あの男にとって、君はいったいどういう意味を持っているのだ？","ENG":"I'm very curious. Who are you to that man?","TWN":"這真是讓人好奇。對那個男人來說，你到底表示什麼？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"자네를 죽이면, 그 남자는 과연 무슨 표정을 지을까?","JPN":"そして君を殺せば、あの男はどんな顔をするだろうか？","ENG":"If you die, what kind of expression will he make?","TWN":"如果殺了你，那個人會露出什麼表情呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"어디 확인해보게, 대령.","JPN":"確認してみよう、大佐。","ENG":"Let's find out, Colonel.","TWN":"上校，來確認一下吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"알겠습니다.","JPN":"承知しました。","ENG":"Yes, sir.","TWN":"遵命。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};